%% =========================================================================
function [Rnew, pnew] = Retract_SE3_Left(R, p, phi, rho)
J = LeftJacobian_SO3(phi);
Rnew = R * Exp_SO3_Rodriguez(phi);
pnew = p + R * J * rho;
end

function [R3, p3] = Mul_SE3(R1, p1, R2, p2)
R3 = R1 * R2;
p3 = p1 + R1 * p2;
end

function [Rinv, pinv] = Inv_SE3(R, p)
Rinv = R';
pinv = -R' * p;
end

function xi = Log_SE3_pair(R, p)
phi = Log_SO3(R);
Jinv = LeftJacobianInv_SO3(phi);
rho = Jinv * p;
xi = [phi; rho];
end

function J = LeftJacobian_SO3(phi)
tt = sqrt(sum(phi.^2) + 1e-6);
phihat = skew_SO3(phi);
A = (1 - cos(tt)) / (tt^2 + 1e-8);
B = (tt - sin(tt)) / (tt^3 + 1e-8);
J = eye(3) + A * phihat + B * (phihat * phihat);
end

function Jinv = LeftJacobianInv_SO3(phi)
tt = sqrt(sum(phi.^2) + 1e-6);
phihat = skew_SO3(phi);
A = 1 / (tt^2 + 1e-8) - (1 + cos(tt)) / (2 * tt * sin(tt) + 1e-8);
Jinv = eye(3) - 0.5 * phihat + A * (phihat * phihat);
end

function w = Log_SO3(R)

t = (trace(R) - 1)/2;
t = if_else(t < -1, -1, t);
t = if_else(t >  1,  1, t);
t = acos( t );
w = t / 2 / sin( sqrt(abs(t^2) + 1e-6) ) * [R(3, 2) - R(2, 3);
                           R(1, 3) - R(3, 1);
                           R(2, 1) - R(1, 2)];
end

