% tt = sqrt(sum(t.^2) + 1e-6);
% K = skew_SO3(t);
% R = eye(3) + sin(tt) / tt * K + (1 - cos(tt)) / (tt^2) * (K * K);
% end

function R = Exp_SO3_Rodriguez(t)
tt = sqrt(sum(t.^2) + 1e-6);
R = eye(3) + sin(tt) / tt * skew_SO3(t) + ...
      (1 - cos(tt)) / (tt^2) * skew_SO3(t)^2;
end


